  if (-not (Test-Path $r)) { continue }
  Get-ChildItem $r -Recurse -EA SilentlyContinue |
    Where-Object { -not $_.PSIsContainer -and ($_.Extension -match '\.(lic|key|license|licx)$' -or $_.Name -match 'licen|лиценз|activation|активац|serial|ключ') } |
    Select-Object -First 50 FullName, Length, LastWriteTime |
    ForEach-Object { L "LIC $($_.LastWriteTime.ToString('yyyy-MM-dd HH:mm')) $($_.Length) $($_.FullName)" }
}

