$ip='26.248.72.177'
$sec = ConvertTo-SecureString '1111' -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential("$ip\usr1cv8", $sec)
$payload = Invoke-Command -ComputerName $ip -Credential $cred -Authentication Negotiate -ScriptBlock {
  $raw = [IO.File]::ReadAllBytes('C:\Windows\Temp\AtolLic_keys.log')
  # find ASCII key markers and extract surrounding bytes
  $ascii = [Text.Encoding]::ASCII.GetString($raw)
  $keys = @('BX1K8-8JCQR-6TLTA','7S79S-44H5M-6TLTA','E0ALY-4SFQ1-6TBPA')
  $chunks = @{}
  foreach ($k in $keys) {
    $idx = 0; $n=0
    while (($i = $ascii.IndexOf($k, $idx)) -ge 0 -and $n -lt 5) {
      $start = [Math]::Max(0, $i - 30)
      $len = [Math]::Min(220, $raw.Length - $start)
      $slice = New-Object byte[] $len
      [Array]::Copy($raw, $start, $slice, 0, $len)
      $chunks["$k#$n"] = [Convert]::ToBase64String($slice)
      $idx = $i + $k.Length; $n++
    }
  }
  $chunks
}
# decode locally with several encodings
$encs = @{
  '1251' = [Text.Encoding]::GetEncoding(1251)
  '866'  = [Text.Encoding]::GetEncoding(866)
  'utf8' = [Text.Encoding]::UTF8
  '1252' = [Text.Encoding]::GetEncoding(1252)
}
foreach ($kv in $payload.GetEnumerator()) {
  Write-Host "`n#### $($kv.Key)"
  $bytes = [Convert]::FromBase64String($kv.Value)
  foreach ($e in $encs.GetEnumerator()) {
    $t = $e.Value.GetString($bytes) -replace '[\x00-\x08\x0B\x0C\x0E-\x1F]',''
    # keep only if has cyrillic
    if ($t -match '[А-Яа-яЁё]') {
      Write-Host "[$($e.Key)] $t"
    }
  }
}
